UPDATE report
SET
    REP_PROC_DT = TO_CHAR(SYSDATE, 'YYYYMMDD'),
    REP_PROC_HM = TO_CHAR(SYSDATE, 'HH24MI'),
    REP_STAT_YN = #{repStatYn}
WHERE REP_NO = #{repNo}

mapper.select:
SELECT * FROM ( SELECT ROWNUM AS rnum, A.* FROM ( SELECT r.REP_NO AS "repNo", r.REP_CN AS "repCn", r.REP_CLSF AS "repClsf", r.REP_STAT_YN AS "repStatYn", r.REP_REG AS "repReg", c.CMT_CN AS "cmtCn", c.CMT_NO AS "cmtNo", r.REG_NO AS "regNo" FROM report r LEFT JOIN cmt c ON r.CMT_NO = c.CMT_NO WHERE 1=1
AND r.REP_STAT_YN = #{repStatYn}
AND r.REP_CLSF = #{repClsf}
ORDER BY r.REP_NO DESC ) A WHERE ROWNUM <= #{pageSize} * #{pageNo} ) WHERE rnum >= #{pageSize} * (#{pageNo} - 1) + 1

SELECT COUNT(*)
FROM report r
WHERE 1=1

    AND r.REP_STAT_YN = #{repStatYn}


    AND r.REP_CLSF = #{repClsf}
